@app.route('/query', methods=['POST'])
def dynamic_query():
    data = request.json
    table_name = data.get('table')
    columns = data.get('columns', '*')
    filters = data.get('filters', {})

    # Securely construct the SQL query
    query = sql.SQL("SELECT {} FROM {} WHERE {}").format(
        sql.SQL(', ').join(map(sql.Identifier, columns.split(','))) if columns != '*' else sql.SQL('*'),
        sql.Identifier(table_name),
        sql.SQL(' AND ').join(
            sql.SQL("{} = {}").format(sql.Identifier(k), sql.Placeholder(k)) for k in filters.keys()
        )
    )

    conn = get_db_connection()
    cur = conn.cursor()
    
    # Execute the query with parameters to prevent SQL injection
    cur.execute(query, filters)
    results = cur.fetchall()
    
    cur.close()
    conn.close()

    return jsonify(results)

